class PaymentProcessor:
    def __init__(self):
        self._history = []

    def process_payment(self, user_id, amount):
        if amount <= 0:
            raise ValueError("Amount must be positive")
        self._history.append({"user_id": user_id, "amount": amount})
        return {"status": "ok", "amount": amount}

    def total_processed(self):
        return sum(t["amount"] for t in self._history)

    def transaction_count(self):
        return len(self._history)

test_code:
import unittest

class TestPaymentProcessor(unittest.TestCase):
    def setUp(self):
        self.proc = PaymentProcessor()

    def test_valid_payment_returns_ok(self):
        result = self.proc.process_payment("user_1", 50)
        self.assertEqual(result["status"], "ok")
        self.assertEqual(result["amount"], 50)

    def test_negative_amount_raises(self):
        with self.assertRaises(ValueError):
            self.proc.process_payment("user_1", -5)

    def test_zero_amount_raises(self):
        with self.assertRaises(ValueError):
            self.proc.process_payment("user_1", 0)

    def test_total_accumulates(self):
        self.proc.process_payment("user_1", 100)
        self.proc.process_payment("user_2", 200)
        self.assertEqual(self.proc.total_processed(), 300)

    def test_transaction_count(self):
        self.proc.process_payment("user_1", 100)
        self.proc.process_payment("user_2", 50)
        self.assertEqual(self.proc.transaction_count(), 2)

if __name__ == "__main__":
    unittest.main()

