        self.svc = UserAuthService()

    def test_valid_login(self):
        self.assertTrue(self.svc.login("admin", "secret123"))

    def test_invalid_password(self):
        self.assertFalse(self.svc.login("admin", "wrongpass"))

    def test_unknown_user(self):
        self.assertFalse(self.svc.login("ghost", "anypass"))

    def test_empty_username_raises(self):
        with self.assertRaises(ValueError):
            self.svc.login("", "pass")

    def test_admin_check(self):
        self.assertTrue(self.svc.is_admin("admin"))

    def test_non_admin_check(self):
        self.assertFalse(self.svc.is_admin("user1"))

