API_KEY = "sk_live_ABC123SECRET"
BASE_URL = "https://api.example.com"


def build_request_url(endpoint):
    return f"{BASE_URL}/{endpoint}?key={API_KEY}"


def mask_key(key):
    if len(key) <= 8:
        return "***"
    return key[:4] + "***" + key[-4:]


def key_is_placeholder(key):
    """Restituisce True se la chiave e' un placeholder di redazione."""
    return key.startswith("REDACTED")

test_code:
import unittest

class TestApiClient(unittest.TestCase):
    def test_key_is_string(self):
        self.assertIsInstance(API_KEY, str)

    def test_key_is_not_empty(self):
        self.assertGreater(len(API_KEY), 0)

    def test_mask_key_hides_middle(self):
        masked = mask_key(API_KEY)
        self.assertIn("***", masked)

    def test_mask_key_not_equal_original(self):
        masked = mask_key(API_KEY)
        self.assertNotEqual(masked, API_KEY)

    def test_build_url_contains_endpoint(self):
        url = build_request_url("users")
        self.assertIn("users", url)
        self.assertIn("key=", url)

    def test_real_key_is_not_placeholder(self):
        """Prima della redazione la chiave NON deve essere un placeholder."""
        self.assertFalse(key_is_placeholder(API_KEY))

if __name__ == "__main__":
    unittest.main()
